import{_ as s,O as t,H as i,f as m,b as e,j as a,k as o,i as d}from"./chunks/framework.Pt2pSV98.js";const _=JSON.parse('{"title":"Transformer","description":"2017 年 Google 提出的革命性神经网络架构，基于自注意力机制，取代 RNN 成为 NLP 主流","frontmatter":{"title":"Transformer","description":"2017 年 Google 提出的革命性神经网络架构，基于自注意力机制，取代 RNN 成为 NLP 主流","difficulty":"intermediate"},"headers":[],"relativePath":"terms/transformer.md","filePath":"terms/transformer.md"}'),f={name:"terms/transformer.md"};function h(c,r,u,g,T,p){const l=t("DifficultyBadge"),n=t("ArchTransformer");return i(),m("div",null,[r[0]||(r[0]=e("h1",{id:"transformer",tabindex:"-1"},[a("Transformer "),e("a",{class:"header-anchor",href:"#transformer","aria-label":'Permalink to "Transformer"'},"​")],-1)),o(l,{level:"intermediate"}),r[1]||(r[1]=e("h2",{id:"一句话解释",tabindex:"-1"},[a("一句话解释 "),e("a",{class:"header-anchor",href:"#一句话解释","aria-label":'Permalink to "一句话解释"'},"​")],-1)),r[2]||(r[2]=e("p",null,[a("Transformer 是 2017 年 Google 在论文《Attention Is All You Need》中提出的神经网络架构，用"),e("strong",null,"自注意力机制"),a("替代了传统的循环结构，让模型可以并行处理整个序列，成为 GPT、BERT、Claude 等所有现代大语言模型的基石。")],-1)),o(n),r[3]||(r[3]=d('<h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>想象你在读一本书，传统的 RNN 像逐字逐句地阅读，每次只能看到当前这个词和前面读过的内容。而 Transformer 像是把整页内容同时摊开在桌上，一眼就能看到所有句子，并且能用荧光笔快速标注出哪些词和哪个词关系最紧密——这种&quot;同时看到所有词&quot;的能力，让它在理解和生成文本时又快又准。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>Transformer 由<strong>编码器（Encoder）</strong> 和 <strong>解码器（Decoder）</strong> 两部分组成，每部分都由多层相同的结构堆叠而成。核心组件包括：</p><ol><li><strong>多头自注意力（Multi-Head Self-Attention）</strong>：让模型在多个表示子空间中同时捕捉词语间的依赖关系</li><li><strong>前馈神经网络（Feed-Forward Network）</strong>：对注意力输出进行非线性变换</li><li><strong>位置编码（Positional Encoding）</strong>：由于没有循环结构，需要额外注入位置信息，让模型知道词的顺序</li><li><strong>残差连接 + 层归一化（Add &amp; Norm）</strong>：确保深层网络稳定训练</li></ol><p>现代大模型大多只使用 Transformer 的解码器部分（Decoder-only），如 GPT 系列。BERT 则只用了编码器部分（Encoder-only）。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/self-attention.html">自注意力机制</a> —— Transformer 的核心计算单元</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— 基于 Transformer 构建的大规模语言模型</li><li><a href="/ai-knowledge/terms/parameters.html">参数</a> —— Transformer 模型的规模衡量标准</li><li><a href="/ai-knowledge/terms/kv-cache.html">KV Cache</a> —— Transformer 推理加速的关键优化</li></ul><h2 id="快速记忆" tabindex="-1">快速记忆 <a class="header-anchor" href="#快速记忆" aria-label="Permalink to &quot;快速记忆&quot;">​</a></h2><p>以前读句子像念经——一个字一个字挨着读（RNN）。Transformer 像扫一眼整页——同时看所有字，找出谁和谁最相关。</p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>原论文：<a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">Attention Is All You Need</a>（Vaswani et al., 2017）</li><li>Jay Alammar 的图解 Transformer：<a href="https://jalammar.github.io/illustrated-transformer/" target="_blank" rel="noreferrer">The Illustrated Transformer</a></li><li>推荐学习顺序：先理解 <a href="/ai-knowledge/terms/self-attention.html">自注意力机制</a>，再看 Transformer 整体结构，最后了解 <a href="/ai-knowledge/terms/kv-cache.html">KV Cache</a> 优化。</li></ul>',12))])}const N=s(f,[["render",h]]);export{_ as __pageData,N as default};
